import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as e,e as t}from"./app-2ea8cdd2.js";const i={},r=t('<h1 id="面试-mybatis" tabindex="-1"><a class="header-anchor" href="#面试-mybatis" aria-hidden="true">#</a> 面试-Mybatis</h1><h3 id="mybatis缓存机制" tabindex="-1"><a class="header-anchor" href="#mybatis缓存机制" aria-hidden="true">#</a> Mybatis缓存机制</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Mybatis缓存机制</b></summary><p><b style="color:#f19977;">答：一级缓存是MyBatis默认开启的缓存机制，它是指在同一个SqlSession内的缓存。当进行相同的查询时，如果该查询的结果已经在当前SqlSession的本地缓存中存在，则直接从缓存中获取结果，而不再去数据库查询。本地缓存的作用域是SqlSession，当SqlSession关闭时，本地缓存也会被清空。<br>二级缓存是指在SqlSessionFactory层面的缓存，它可以被多个SqlSession共享。当多个SqlSession执行相同的查询时，如果查询结果已经存在于二级缓存中，则直接从缓存中获取结果，而不会再去数据库查询。二级缓存的作用域是SqlSessionFactory，在整个应用的生命周期内有效。需要注意的是，二级缓存需要在MyBatis的配置文件中明确地配置开启。</b></p></details><h3 id="和-区别" tabindex="-1"><a class="header-anchor" href="#和-区别" aria-hidden="true">#</a> #{}和${}区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：#{}和${}区别</b></summary><p><b style="color:#f19977;">答：两者都是实现动态SQL的一种方式。#{}相当于占位符可以防止SQL注入。使用${}方式传参，相当于直接把参数拼接到原始的SQL里面，不能防止SQL注入。</b></p></details>',5),o=[r];function l(n,c){return a(),e("div",null,o)}const b=s(i,[["render",l],["__file","面试-Mybatis.html.vue"]]);export{b as default};
